#include <stdio.h>
#include <math.h>

static void gauss_legendre\(int n, double *nodes, double *weights\) {
    for \(int i = 0; i < n; i++\) {
        double x = cos\(M_PI * \(i + 0.75\) / \(n + 0.5\)\);
        for \(int iter = 0; iter < 20; iter++\) {
            double p0 = 1, p1 = x;
            for \(int j = 2; j <= n; j++\) {
                double p2 = \(\(2*j-1\)*x*p1 - \(j-1\)*p0\) / j;
                p0 = p1; p1 = p2;
            }
            double dp = n * \(x*p1 - p0\) / \(x*x - 1\);
            x -= p1 / dp;
        }
        nodes[i] = x;
        double p0 = 1, p1 = x;
        for \(int j = 2; j <= n; j++\) {
            double p2 = \(\(2*j-1\)*x*p1 - \(j-1\)*p0\) / j;
            p0 = p1; p1 = p2;
        }
        weights[i] = 2.0 / \(\(1 - x*x\) * n*n * p0*p0\);
    }
}

int main\(\) {
    int n = 20;
    double nodes[20], weights[20];
    gauss_legendre\(n, nodes, weights\);

    double sum_w = 0;
    for \(int i = 0; i < n; i++\) {
        sum_w += weights[i];
        printf\("  node[%d] = %12.8f  w[%d] = %12.8f\\n", i, nodes[i], i, weights[i]\);
    }
    printf\("Sum of weights = %.15f \(should be 2.0\)\\n", sum_w\);

    /* Test angular integration: ∫ dΩ/\(4π\) = 1 */
    int n_phi = 2*n;
    double dphi = 2*M_PI / n_phi;
    double solid_angle_sum = 0;
    for \(int it = 0; it < n; it++\) {
        for \(int ip = 0; ip < n_phi; ip++\) {
            double wt = weights[it] * dphi / \(4*M_PI\);
            solid_angle_sum += wt;
        }
    }
    printf\("Solid angle sum = %.15f \(should be 1.0\)\\n", solid_angle_sum\);

    /* Test: ∫ \(x² + y² + z²\) dΩ/\(4π\) should be 1 */
    double xyz_sum = 0;
    for \(int it = 0; it < n; it++\) {
        double ct = nodes[it];
        double st = sqrt\(1.0 - ct*ct\);
        for \(int ip = 0; ip < n_phi; ip++\) {
            double phi = ip * dphi;
            double x = st*cos\(phi\), y = st*sin\(phi\), z = ct;
            double wt = weights[it] * dphi / \(4*M_PI\);
            xyz_sum += wt * \(x*x + y*y + z*z\);
        }
    }
    printf\("⟨x²+y²+z²⟩ = %.15f \(should be 1.0\)\\n", xyz_sum\);

    return 0;
}
