/* Quick fine scan of [0, m_pi^2] for bound breathing modes */
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

#define M_PI 3.14159265358979323846

/* Minimal profile reader */
typedef struct { int n; double *r, *f, *fp; double dr; } Profile;

static int read_profile\(const char *fname, Profile *prof\) {
    FILE *fp = fopen\(fname, "r"\);
    if \(!fp\) return -1;
    int cap = 16384;
    prof->r = malloc\(cap*sizeof\(double\)\);
    prof->f = malloc\(cap*sizeof\(double\)\);
    prof->fp = malloc\(cap*sizeof\(double\)\);
    int n = 0; char line[512];
    while \(fgets\(line, sizeof\(line\), fp\)\) {
        if \(line[0] == '#'\) continue;
        double rv, fval, fpval = 0, d1, d2, d3;
        int nc = sscanf\(line, "%lf %lf %lf %lf %lf %lf", &rv, &fval, &fpval, &d1, &d2, &d3\);
        if \(nc < 2\) continue;
        if \(n >= cap\) { cap *= 2; prof->r = realloc\(prof->r, cap*8\); prof->f = realloc\(prof->f, cap*8\); prof->fp = realloc\(prof->fp, cap*8\); }
        prof->r[n] = rv; prof->f[n] = fval; prof->fp[n] = fpval; n++;
    }
    fclose\(fp\); prof->n = n; prof->dr = \(n>1\) ? prof->r[1]-prof->r[0] : 0.001;
    return 0;
}

static void interp_profile\(const Profile *p, double r, double *fout, double *fpout\) {
    if \(r <= p->r[0]\) { *fout = p->f[0]; *fpout = p->fp[0]; return; }
    if \(r >= p->r[p->n-1]\) { *fout = p->f[p->n-1]; *fpout = p->fp[p->n-1]; return; }
    int lo=0, hi=p->n-1;
    while \(hi-lo>1\) { int mid=\(lo+hi\)/2; if\(p->r[mid]<=r\) lo=mid; else hi=mid; }
    double t=\(r-p->r[lo]\)/\(p->r[hi]-p->r[lo]\);
    *fout = p->f[lo]+t*\(p->f[hi]-p->f[lo]\);
    *fpout = p->fp[lo]+t*\(p->fp[hi]-p->fp[lo]\);
}

static double compute_fpp\(double r, double f, double fp, double c4, double m_pi2\) {
    double sf=sin\(f\), sf2=sf*sf, s2f=sin\(2*f\);
    double denom=r*r+2*c4*sf2;
    if \(denom<1e-30\) return 0.0;
    return \(s2f*\(1.0+c4*sf2/\(r*r+1e-30\)\)+m_pi2*r*r*sf-2*fp*r-c4*fp*fp*s2f\)/denom;
}

/* Build potential arrays */
static double *gP, *gW, *gm, *gr;
static int gnr;
static double gdr;

static void build_pot\(const Profile *prof, double c4, double m_pi2, int nr, double r_max\) {
    gnr = nr; gdr = r_max/nr;
    gr = calloc\(nr+1, sizeof\(double\)\);
    gP = calloc\(nr+1, sizeof\(double\)\);
    gW = calloc\(nr+1, sizeof\(double\)\);
    gm = calloc\(nr+1, sizeof\(double\)\);
    for \(int ir = 0; ir <= nr; ir++\) {
        double r = \(ir==0\) ? 1e-6 : ir*gdr;
        gr[ir] = r;
        double f, fp; interp_profile\(prof, r, &f, &fp\);
        double fpp = compute_fpp\(r, f, fp, c4, m_pi2\);
        double sf=sin\(f\), sf2=sf*sf, c2f=cos\(2*f\), s2f=sin\(2*f\);
        double r2=r*r;
        gP[ir] = 2*r2 + 4*c4*sf2;
        gm[ir] = r2 + 2*c4*sf2;
        double Q = 4*c2f*\(1+c4*fp*fp\) + 4*c4*sf2*\(1+2*c2f\)/\(r2+1e-30\);
        double Bp = 4*c4*\(fpp*s2f + 2*fp*fp*c2f\);
        gW[ir] = Q - Bp + m_pi2*r2*cos\(f\);
    }
}

static double compute_nu\(void\) {
    double W0 = gW[0], disc = 1.0+2.0*W0;
    return \(disc<0\) ? 0 : \(-1.0+sqrt\(disc\)\)/2.0;
}

static void interp_pot\(double r, double *P, double *W, double *m\) {
    double idx=r/gdr; int i0=\(int\)idx;
    if\(i0<0\) i0=0; if\(i0>=gnr\) i0=gnr-1;
    int i1=\(i0<gnr\)?i0+1:i0; double t=idx-i0;
    if\(t<0\) t=0; if\(t>1\) t=1;
    *P=\(1-t\)*gP[i0]+t*gP[i1]; *W=\(1-t\)*gW[i0]+t*gW[i1]; *m=\(1-t\)*gm[i0]+t*gm[i1];
}

static double shoot\(double lambda\) {
    double nu = compute_nu\(\);
    double delta = gr[0];
    double g = pow\(delta, nu\);
    double p = 2.0*nu*pow\(delta, nu+1.0\);
    for \(int ir = 0; ir < gnr; ir++\) {
        double r = gr[ir]; if\(r<1e-10\) r=1e-10;
        double dr = gdr;
        double P,W,m, dg,dp;
        /* RK4 */
        interp_pot\(r, &P, &W, &m\); if\(P<1e-15\) P=1e-15;
        double k1g=p/P, k1p=\(W-lambda*m\)*g;
        interp_pot\(r+0.5*dr, &P, &W, &m\); if\(P<1e-15\) P=1e-15;
        double g2=g+0.5*dr*k1g, p2=p+0.5*dr*k1p;
        double k2g=p2/P, k2p=\(W-lambda*m\)*g2;
        double g3=g+0.5*dr*k2g, p3=p+0.5*dr*k2p;
        double k3g=p3/P, k3p=\(W-lambda*m\)*g3;
        interp_pot\(r+dr, &P, &W, &m\); if\(P<1e-15\) P=1e-15;
        double g4=g+dr*k3g, p4=p+dr*k3p;
        double k4g=p4/P, k4p=\(W-lambda*m\)*g4;
        g += \(dr/6.0\)*\(k1g+2*k2g+2*k3g+k4g\);
        p += \(dr/6.0\)*\(k1p+2*k2p+2*k3p+k4p\);
        if \(fabs\(g\)>1e30 || fabs\(p\)>1e30\) { g*=1e-20; p*=1e-20; }
    }
    return g;
}

int main\(void\) {
    Profile prof;
    read_profile\("data/profiles/profile_massive_e1_mpi0.398.dat", &prof\);
    double c4=2.0, m_pi2=0.398*0.398;
    build_pot\(&prof, c4, m_pi2, 8000, 15.0\);
    printf\("nu = %.4f\\n", compute_nu\(\)\);
    printf\("m_pi^2 = %.6f \(threshold\)\\n", m_pi2\);
    printf\("\\nFine scan [0, 0.20] with 10000 points:\\n"\);
    int n_scan = 10000;
    double g_prev = shoot\(0.0\);
    int found = 0;
    for \(int is = 1; is <= n_scan; is++\) {
        double lam = 0.20 * is / n_scan;
        double g_cur = shoot\(lam\);
        if \(g_prev * g_cur < 0\) {
            /* Bisect */
            double lo = 0.20*\(is-1\)/n_scan, hi = lam;
            double g_lo = g_prev;
            for \(int bi=0; bi<100; bi++\) {
                double mid=0.5*\(lo+hi\);
                double gm=shoot\(mid\);
                if\(gm*g_lo>0\) { lo=mid; g_lo=gm; } else hi=mid;
                if\(hi-lo<1e-12\) break;
            }
            double ev=0.5*\(lo+hi\);
            printf\("  Found eigenvalue: lambda=%.10f  omega=%.6f  %s\\n",
                   ev, sqrt\(ev\), \(ev < m_pi2\) ? "** BOUND **" : "\(continuum\)"\);
            found++;
        }
        g_prev = g_cur;
    }
    if \(!found\) printf\("  No eigenvalues found in [0, 0.20]\\n"\);
    printf\("\\nAlso scan [-1, 0] for instabilities:\\n"\);
    n_scan = 5000; g_prev = shoot\(-1.0\); found = 0;
    for \(int is = 1; is <= n_scan; is++\) {
        double lam = -1.0 + 1.0*is/n_scan;
        double g_cur = shoot\(lam\);
        if \(g_prev * g_cur < 0\) {
            double lo = -1.0+\(is-1\)*1.0/n_scan, hi = lam, g_lo = g_prev;
            for \(int bi=0; bi<100; bi++\) { double mid=0.5*\(lo+hi\); double gm=shoot\(mid\); if\(gm*g_lo>0\){lo=mid;g_lo=gm;} else hi=mid; if\(hi-lo<1e-12\) break; }
            printf\("  Found: lambda=%.10f  UNSTABLE\\n", 0.5*\(lo+hi\)\);
            found++;
        }
        g_prev = g_cur;
    }
    if \(!found\) printf\("  No instabilities found \(all lambda > 0\)\\n"\);
    return 0;
}
