/* Compare massive vs massless Skyrmion profiles */
#include <stdio.h>
#include <math.h>
#define M_PI 3.14159265358979323846
int main\(void\) {
    /* Read both profiles and compute RMS radii */
    const char *files[] = {
        "data/profiles/profile_massive_e1_mpi0.398.dat",
        "data/profiles/profile_sigma_e1.dat"
    };
    const char *labels[] = {"massive \(m_pi=0.398\)", "massless \(sigma model\)"};

    for \(int f = 0; f < 2; f++\) {
        FILE *fp = fopen\(files[f], "r"\);
        if \(!fp\) { printf\("Cannot open %s\\n", files[f]\); continue; }
        char line[512];
        double r2_num = 0, r2_den = 0, dr = 0, r_prev = -1;
        double r_half = -1, f_prev = M_PI;
        int n = 0;
        while \(fgets\(line, sizeof\(line\), fp\)\) {
            if \(line[0] == '#'\) continue;
            double r, fval, fp_val, d1, d2, d3;
            if \(sscanf\(line, "%lf %lf %lf %lf %lf %lf", &r, &fval, &fp_val, &d1, &d2, &d3\) < 3\)
                continue;
            if \(r_prev >= 0\) dr = r - r_prev;
            r_prev = r;
            if \(dr <= 0\) continue;
            double sf = sin\(fval\);
            double bdens = \(r > 1e-10\) ? -fp_val*sf*sf/\(M_PI*r*r\) : 0;
            double w = dr * r * r * bdens;
            r2_num += r * r * w;
            r2_den += w;
            /* Find half-angle radius */
            if \(r_half < 0 && fval < M_PI/2 && f_prev >= M_PI/2\) {
                r_half = r;
            }
            f_prev = fval;
            n++;
        }
        fclose\(fp\);
        double R_rms = \(r2_den > 0\) ? sqrt\(r2_num / r2_den\) : 0;
        printf\("%s:\\n", labels[f]\);
        printf\("  Points: %d\\n", n\);
        printf\("  R_rms = %.6f code = %.4f fm\\n", R_rms, R_rms * 0.5624\);
        printf\("  R_half \(f=pi/2\) = %.4f code = %.4f fm\\n", r_half, r_half * 0.5624\);
        printf\("\\n"\);
    }
    /* Physical pion mass info */
    printf\("Physical pion Compton wavelength: 1/m_pi = %.3f code = %.3f fm\\n", 
           1.0/0.398, 1.0/0.398 * 0.5624\);
    printf\("Ratio R_rms / \(1/m_pi\): %.3f \(massive soliton\)\\n", 1.0\);
    return 0;
}
