#include <stdio.h>
#include <math.h>
/* Updated parameter fit with massive pion */
int main\(void\) {
    /* Massless results */
    double K0 = 103.13, CR0 = 1.4961;
    double rho4_e2_0 = 4.00 / \(K0 * CR0\);

    /* Massive results at e=1, rho0=1, mpi=0.398 */
    double Km = 110.19, CRm = 1.264;
    double rho4_e2_m = 4.00 / \(Km * CRm\);

    printf\("=== Parameter Fit: Massless vs Massive ===\\n\\n"\);
    printf\("Physical constraint: M_p * r_p / hbar*c = 4.00\\n\\n"\);

    printf\("%-25s %-12s %-12s\\n", "Quantity", "Massless", "Massive"\);
    printf\("%-25s %-12s %-12s\\n", "--------", "--------", "-------"\);
    printf\("%-25s %-12.2f %-12.2f\\n", "K = E_sol*e/rho0^3", K0, Km\);
    printf\("%-25s %-12.4f %-12.4f\\n", "C_R = R_rms*e/rho0", CR0, CRm\);
    printf\("%-25s %-12.4f %-12.4f\\n", "K * C_R", K0*CR0, Km*CRm\);
    printf\("%-25s %-12.5f %-12.5f\\n", "rho0^4/e^2", rho4_e2_0, rho4_e2_m\);

    printf\("\\n=== Standard Skyrme Convention ===\\n"\);
    printf\("\(E4 coeff = 1/\(2e_std^2\), independent of F_pi\)\\n\\n"\);

    /* In standard convention: e_std = e/sqrt\(2*rho0^2\) * something...
     * Actually: our c4 = 2*rho0^2/e^2, standard c4_std = 2/e_std^2
     * So rho0^2/e^2 = 1/e_std^2, giving e_std = e/rho0
     * And F_pi = 2*rho0 \(standard relation\)
     * Constraint: rho0^4/e^2 = rho0^2 * rho0^2/e^2 = rho0^2/e_std^2 = \(F_pi/2\)^2/e_std^2
     * -> F_pi^2/\(4*e_std^2\) = rho4_e2
     * -> F_pi/e_std = 2*sqrt\(rho4_e2\)
     * Also: E_sol = K * rho0^3/e = K * rho0^2 * rho0/e = K/\(e_std * F_pi/2\) * \(F_pi/2\)^2
     *       Hmm, let me just parameterize by e_std
     * rho0 = F_pi/2, e = e_std * rho0 = e_std * F_pi/2
     * rho0^4/e^2 = \(F_pi/2\)^4 / \(e_std*F_pi/2\)^2 = F_pi^2/\(4*e_std^2\)
     * So F_pi = 2*e_std*sqrt\(rho4_e2\)
     * And E_sol = K*rho0^3/e = K*\(F_pi/2\)^3/\(e_std*F_pi/2\) = K*F_pi^2/\(8*e_std\)
     * M_p = E_sol in physical units, but we need the conversion factor.
     * 
     * Simpler: from E_sol*R_rms = 4.00 \(dimensionless in hbar*c=1 units\)
     * E_sol = K*rho0^3/e, R_rms = CR*rho0/e
     * E_sol*R_rms = K*CR*rho0^4/e^2 = 4.00
     * 
     * Also E_sol = M_p, so Lambda_E = M_p/E_sol_code
     * And R_rms_phys = r_p, so Lambda_L = r_p/R_rms_code
     * 
     * For e_std: e_std = e/rho0, so if we set e=1 in code:
     * rho0 = 1/e_std \(code convention e=1\)
     * rho0^4/e^2 = rho0^4 = 1/e_std^4
     * So e_std = \(1/rho4_e2\)^\(1/4\)
     */

    double e_std_0 = pow\(1.0/rho4_e2_0, 0.25\);
    double e_std_m = pow\(1.0/rho4_e2_m, 0.25\);

    /* F_pi: in standard convention, F_pi = 2*rho0. With rho0 = 1/e_std and
     * the physical scale: Lambda_L = r_p/R_rms = 0.841/\(CR/e_std\)
     * F_pi_phys = 2*rho0 * Lambda_E / hbar*c... this needs care.
     * 
     * Actually: F_pi_phys = hbar*c * F_pi_code / Lambda_L
     * where F_pi_code = 2*rho0 and Lambda_L is in fm.
     * 
     * Lambda_L = r_p / R_rms_code = 0.8414 / \(CR/e_std\) = 0.8414*e_std/CR
     * Lambda_E = M_p / E_sol_code = 938.272 / \(K/e_std^3\) = 938.272*e_std^3/K
     * hbar*c = 197.327 MeV*fm
     * F_pi_phys = hbar*c * 2*rho0 / \(Lambda_L * hbar*c\) ... hmm that's dimensionally wrong
     * 
     * The physical F_pi relates to the code quantities by:
     * F_pi_phys^2 = rho0^2 * Lambda_E^2 / ... 
     * 
     * Simpler: from ANW \(1983\), the Skyrmion mass is M_N = 6*pi^2*F_pi/\(e_std\)
     * times the numerical factor E/E_FB = 1.232.
     * So M_p = \(6*pi^2*F_pi/e_std\) * 1.232... that's not right either.
     * 
     * Standard: E_std = \(F_pi/4e_std\) * 12*pi^2 * E/E_FB_std
     * where E/E_FB_std = 1.232 for massless, and FB_std = 12*pi^2.
     * So M_p = \(F_pi * 12*pi^2 / \(4*e_std\)\) * 1.232
     * -> F_pi = M_p * 4 * e_std / \(12*pi^2 * 1.232\)
     * 
     * But with pion mass, E/E_FB changes \(it's 1.316 at physical m_pi\).
     * The FB bound itself doesn't change \(it's topological\).
     * 
     * Let me use: M_p = E_FB_std * \(E/E_FB\) * F_pi/\(4*e_std\)
     * where E_FB_std = 12*pi^2
     * M_p = 12*pi^2 * \(E/E_FB\) * F_pi / \(4*e_std\)
     * F_pi = 4 * M_p * e_std / \(12*pi^2 * \(E/E_FB\)\)
     */

    double M_p = 938.272; /* MeV */
    double r_p = 0.8414; /* fm */
    double hbarc = 197.327; /* MeV*fm */

    /* E/E_FB for each case */
    double ratio0 = 1.2316; /* massless */
    double ratiom = 1.3157; /* massive */

    double Fpi0 = 4*M_p*e_std_0 / \(12*M_PI*M_PI*ratio0\);
    double Fpim = 4*M_p*e_std_m / \(12*M_PI*M_PI*ratiom\);

    printf\("%-25s %-12.4f %-12.4f\\n", "e_std", e_std_0, e_std_m\);
    printf\("%-25s %-12.1f %-12.1f\\n", "F_pi \(MeV\)", Fpi0, Fpim\);
    printf\("%-25s %-12.1f %-12.1f\\n", "F_pi exp \(MeV\)", 92.1, 92.1\);

    /* Code unit conversion at e=1, rho0=1 */
    printf\("\\n=== Code Units \(e=1, rho0=1\) ===\\n\\n"\);

    double Esol0 = K0, Esolm = Km;  /* at e=1, rho0=1 */
    double Rrms0 = CR0, Rrmsm = CRm;

    double LE0 = M_p / Esol0;   /* MeV per code energy */
    double LEm = M_p / Esolm;
    double LL0 = r_p / Rrms0;   /* fm per code length */
    double LLm = r_p / Rrmsm;

    printf\("%-25s %-12.3f %-12.3f\\n", "1 code E \(MeV\)", LE0, LEm\);
    printf\("%-25s %-12.4f %-12.4f\\n", "1 code L \(fm\)", LL0, LLm\);
    printf\("%-25s %-12.4f %-12.4f\\n", "1 code T \(10^-24 s\)", 
           LL0/\(3e8*1e15\)*1e24, LLm/\(3e8*1e15\)*1e24\);
    printf\("%-25s %-12.1f %-12.1f\\n", "Soliton mass \(MeV\)", 
           Esol0*LE0, Esolm*LEm\);
    printf\("%-25s %-12.3f %-12.3f\\n", "R_rms \(fm\)", 
           Rrms0*LL0, Rrmsm*LLm\);

    /* Pion mass consistency check */
    printf\("\\n=== Pion Mass Consistency ===\\n"\);
    double mpi_phys = 139.570; /* MeV */
    double mpi_code_0 = mpi_phys * LL0 / hbarc; /* in 1/code_length */
    double mpi_code_m = mpi_phys * LLm / hbarc;
    printf\("m_pi physical: %.1f MeV\\n", mpi_phys\);
    printf\("m_pi code \(massless fit\): %.4f 1/code_length\\n", mpi_code_0\);
    printf\("m_pi code \(massive fit\):  %.4f 1/code_length\\n", mpi_code_m\);
    printf\("Used in solver: 0.398 \(from massless fit\)\\n"\);
    printf\("Self-consistent value: %.4f \(should re-solve iteratively\)\\n", mpi_code_m\);

    /* Particle masses in code units */
