/* Quick test: verify pion mass gradient by finite-difference */
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include "src/field.h"

int main\(void\) {
    int N = 16;
    double L = 4.0;
    double eps = 1e-5;

    Params params = {1.0, 0.0, 1e6, 0.0, 0.0, 1.0, 0.5*0.5};  /* m_pi=0.5 */

    Field *f = field_alloc\(N, L\);
    /* Initialize with random field near vacuum */
    srand\(42\);
    for \(int i = 0; i < N*N*N; i++\) {
        f->psi[i].s = 1.0 + 0.05*\(rand\(\)/\(double\)RAND_MAX - 0.5\);
        f->psi[i].f1 = 0.05*\(rand\(\)/\(double\)RAND_MAX - 0.5\);
        f->psi[i].f2 = 0.05*\(rand\(\)/\(double\)RAND_MAX - 0.5\);
        f->psi[i].f3 = 0.05*\(rand\(\)/\(double\)RAND_MAX - 0.5\);
    }

    /* Compute analytical gradient */
    Multivector *force = \(Multivector*\)calloc\(N*N*N, sizeof\(Multivector\)\);
    field_gradient\(f, &params, force\);

    /* Test at a few points */
    int test_pts[] = {idx\(N,3,5,7\), idx\(N,8,2,11\), idx\(N,1,14,6\)};
    double max_err = 0;

    for \(int t = 0; t < 3; t++\) {
        int ix = test_pts[t];
        /* Numerical gradient for s component */
        double orig = f->psi[ix].s;
        f->psi[ix].s = orig + eps;
        Energy ep = field_energy\(f, &params\);
        f->psi[ix].s = orig - eps;
        Energy em = field_energy\(f, &params\);
        f->psi[ix].s = orig;

        double num_s = -\(ep.Etotal - em.Etotal\)/\(2*eps*f->h*f->h*f->h\);
        double ana_s = force[ix].s;
        double err_s = \(ana_s != 0\) ? fabs\(num_s - ana_s\)/fabs\(ana_s\) : fabs\(num_s - ana_s\);

        /* f1 component */
        orig = f->psi[ix].f1;
        f->psi[ix].f1 = orig + eps;
        ep = field_energy\(f, &params\);
        f->psi[ix].f1 = orig - eps;
        em = field_energy\(f, &params\);
        f->psi[ix].f1 = orig;

        double num_f1 = -\(ep.Etotal - em.Etotal\)/\(2*eps*f->h*f->h*f->h\);
        double ana_f1 = force[ix].f1;
        double err_f1 = \(ana_f1 != 0\) ? fabs\(num_f1 - ana_f1\)/fabs\(ana_f1\) : fabs\(num_f1 - ana_f1\);

        printf\("Point %d: s: ana=%+.6e num=%+.6e err=%.1e | f1: ana=%+.6e num=%+.6e err=%.1e\\n",
               t, ana_s, num_s, err_s, ana_f1, num_f1, err_f1\);
        if \(err_s > max_err\) max_err = err_s;
        if \(err_f1 > max_err\) max_err = err_f1;
    }

    printf\("\\nMax relative error: %.2e\\n", max_err\);
    printf\("%s\\n", max_err < 1e-4 ? "PION MASS GRADIENT: PASS" : "PION MASS GRADIENT: FAIL"\);

    free\(force\);
    field_free\(f\);
    return 0;
}
